body.script:
promise_test(async () => {
  const t1 = document.getElementById('t1');

  // Initial state check
  assert_not_equals(getComputedStyle(t1).backgroundColor, 'rgb(0, 255, 0)', 't1 initial');

  // Move to t1 and pointerDown (active)
  let actions = new test_driver.Actions();
  await actions.pointerMove(0, 0, {origin: t1})
               .pointerDown()
               .send();
  assert_equals(getComputedStyle(t1).backgroundColor, 'rgb(0, 255, 0)', 't1 active');

  // pointerUp (inactive)
  actions = new test_driver.Actions();
  await actions.pointerUp()
               .send();
  assert_not_equals(getComputedStyle(t1).backgroundColor, 'rgb(0, 255, 0)', 't1 released');
}, "Verify :active styles");
